    }

    public static void main(String[] args) {
        // Default paths (editable by user)
        String inputPath = "./src/main/java";
        String outputPath = "./src/main/gen";

        if (args.length > 0) inputPath = args[0];
        if (args.length > 1) outputPath = args[1];

        Launcher launcher = new Launcher();
        launcher.addInputResource(inputPath);
        launcher.setSourceOutputDirectory(outputPath);

        // =======================================================================
        // CRITICAL CONFIGURATION: PRESERVE FORMATTING (Sniper) & NO-CLASSPATH
        // =======================================================================

        // 1. Enable comments
        launcher.getEnvironment().setCommentEnabled(true);

        // 2. Force Sniper Printer manually to preserve original formatting
        launcher.getEnvironment().setPrettyPrinterCreator(
            () -> new SniperJavaPrettyPrinter(launcher.getEnvironment())
        );

        // 3. Enable NoClasspath mode (Defensive handling required in Processor)
        launcher.getEnvironment().setNoClasspath(true);

        // =======================================================================

        launcher.addProcessor(new MigrationProcessor());

        try {
            launcher.run();
            System.out.println("Migration finished. Output in: " + outputPath);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
